actions.script:
def ef = ec.entity.find("org.apache.ofbiz.product.product.Product") def ev = ef.makeEntityDynamicView()
ev.addMemberEntity("p" ,"org.apache.ofbiz.product.product.Product" , null ,null ,null) ev.addMemberEntity("gi" , "org.apache.ofbiz.product.product.GoodIdentification" , "p" , true , ["productId": "productId"])
ev.addAlias("p" , "productId") ev.addAlias("p" , "internalName" ) ev.addAlias("p" ,"productTypeId") ev.addAlias("gi" ,"goodIdentificationTypeId") ev.addAlias("gi" , "idValue")
def conditionFactory = ec.entity.conditionFactory
def cond = conditionFactory.makeCondition([ conditionFactory.makeCondition("productTypeId",org.moqui.entity.EntityCondition.ComparisonOperator.EQUALS,"FINISHED_GOOD"), conditionFactory.makeCondition("idValue", org.moqui.entity.EntityCondition.ComparisonOperator.EQUALS,null), conditionFactory.makeCondition("goodIdentificationTypeId",org.moqui.entity.EntityCondition.ComparisonOperator.EQUALS,"ERP_ID")], org.moqui.entity.EntityCondition.JoinOperator.AND)
def productList = ef.condition(cond).selectFields(["productId" ,"internalNAme" ,"productTypeId" ,"goodIdentificationTypeId"]).list() ec.logger.info("Retrieved ProductList: ${productList}")

def ef = ec.entity.find("org.apache.ofbiz.order.order.OrderHeader") def ev = ef.makeEntityDynamicView()
ev.makeMemberEntity("OH" , "org.apache.ofbiz.order.order.OrderHeader" , null , null ,null) ev.makeMemberEntity("OIS" ,"org.apache.ofbiz.order.order.OrderItemShipGroup" ,"OH" , false , ["orderId":"orderId"]) ev.makeMemberEntity("AD" ,"org.apache.ofbiz.order.order.OrderAdjustment" ,"OH" , true , ["orderId":"orderId"])
ev.addAlias("OIS" ,"SHIPMENT_METHOD_TYPE_ID") ev.addAlias("OH","SALES_CHANNEL_ENUM_ID") ev.addAlias("AD", "orderId" ) ev.addAlias("AD" , "Amount" ,"TotalAmount" ,"SUM") ev.contion("SHIPMENT_METHOD_TYPE_ID","STOREPICKUP") ef.condition("SALES_CHANNEL_ENUM_ID" , "WEB_SALES_CHANNEL") def tempTable = ef.selectField(["orderId" ,"TotalAmount"]).groupBy("orderID").list();
def ef1 = ec.entity.find("org.apache.ofbiz.order.order.OrderHeader") def ev1 = ef1.makeEntityDynamicView()
ev1.makeMemberEntity("OH","org.apache.ofbiz.order.order.OrderHeader" ,null , null ,null) ev1.makeMemberEntity("OA" , "ec.tempTable" , "OH" , false , ["orderId" : "orderId"]) ev1.makeMemberEntity("OS" , "org.apache.obiz.order.order.OrderStatus" ,"OH" , true , ["orderId":"orderId"])
ev1.addAlias("OA" , "orderId" ,"orderId" , "count") ev1.addAlias("OS" ,"StatusDateTime") ev1.addAlias("OS" ,"StatusId") ev1.addAlias("OA" , "TotalAmount") ev1.addAlias("OH","GrandTotal") ev1.addPqExprAlias("Revenue", "SUM(IFNULL(OH.GRAND_TOTAL, 0) - IFNULL(OA.OTHER_CHARGES, 0))", "number-integer", null)
def conditionFactory = ec.entity.conditionFactory
cond1 = conditionFactory.makeCondition( makeCondition("StatusDateTime" , org.moqui.entity.EntityCondition.ComparisonOperator.GREATER_THAN_EQUALS_TO ,"2025-01-01") org.moqui.entity.EntityCondition.JoinOperator.AND , makeCondition("StatusDateTime" , org.moqui.entity.EntityCondition.ComparisonOperator.LESS_THAN_EQUALS_TO ,"2026-06-01") ) ev1.condition(cond1) ev1.condition("Status_Id","ITEM_COMPLETED")
bopisOrderRevenue = ev1.selectField(["orderId","Revenue"]).list()
ec.logger.info("${bopisOrderRevenue}")
